#include<bits/stdc++.h>
using namespace std;
struct node
{
    int a[20001],len;
    node()
    {
        memset(a,0,sizeof(0));
    }
    void operator=(int x)
    {
        int cnt=0;
        while(x)
        {
            a[++cnt]=x%10;
            x/=10;
        }
        len=cnt;
    }
    node operator*(const int&b)const
    {
        node c;
        memcpy(c.a,a,sizeof(a));
        for(int i=1;i<=len;i++)
        {
            c.a[i]*=b;
        }
        int l=len;
        for(int i=1;i<=len+10;i++)
        {
            if(c.a[i])
            {
                l=i;
            }
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        c.len=l;
        return c;
    }
    node operator-(const node&b)const
    {
        bool jw=false;
        node c;
        memcpy(c.a,a,sizeof(c));
        for(int i=1;i<=len;i++)
        {
            if(jw)
            {
                c.a[i]--;
                jw=false;
            }
            if(c.a[i]<b.a[i])
            {
                jw=true;
                c.a[i]+=10;
            }
            c.a[i]-=b.a[i];
        }
        c.len=len;
        while(c.a[c.len]==0&&c.len>0)
        {
            c.len--;
        }
        return c;
    }
    void print()const
    {
        int cnt=len;
        if(cnt==0)
        {
            printf("0");
        }
        else
        {
            for(int i=cnt;i>=1;i--)
            {
                printf("%d",a[i]);
            }
        }
    }
};
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    node a;
    a=1;
    for(int i=1;i<=n+2;i++)
    {
        a=a*i;
    }
    for(int i=n+3;i>=n-m+4;i--)
    {
        a=a*i;
    }
    node b;
    b=1;
    for(int i=1;i<=n+1;i++)
    {
        b=b*i;
    }
    b=b*2;
    for(int i=n+2;i>=n-m+3;i--)
    {
        b=b*i;
    }
    node c=a-b;
    c.print();
    return 0;
}
